// // This module converts input signals according to the following rules:
// - When A1_N and A2_N are both low, X should be set to B1.
// - When A1_N is low and A2_N is high, X should be set to B2.
// - When A1_N is high and A2_N is low, X should be set to the inverse of B1.
// - When A1_N and A2_N are both high, X should be set to the inverse of B2.
module signal_converter(
    input A1_N,
    input A2_N,
    input B1,
    input B2,
    output reg X
);

    always @(*) begin
        if (A1_N==0 && A2_N==0) begin
            X = B1;
        end else if (A1_N==0 && A2_N==1) begin
            X = B2;
        end else if (A1_N==1 && A2_N==0) begin
            X = ~B1;
        end else if (A1_N==1 && A2_N==1) begin
            X = ~B2;
        end
    end

endmodule

